const MAX = 20;
const raw = typeof msg.payload === 'string' ? JSON.parse(msg.payload) : msg.payload;
const p = raw && raw.payload && raw.payload.end_device_ids ? raw.payload : raw;
if (!p || !p.end_device_ids || !p.uplink_message) return null;
const um = p.uplink_message;
const deviceId = p.end_device_ids.device_id;
const nameAttr = um.attributes?.name ?? p.attributes?.name;
const sensorName = (nameAttr != null && String(nameAttr).trim() !== '') ? String(nameAttr).trim() : deviceId;
const receivedAtRaw = p.received_at ?? um.received_at;
const ts = receivedAtRaw != null ? new Date(receivedAtRaw).getTime() : Date.now();
const rx = um.rx_metadata?.[0] || {};
const locUser = um.locations?.user || p.locations?.user || null;
const locGw = rx.location || null;
const lbp = p.last_battery_percentage ?? um.last_battery_percentage;
const bpVal = lbp && (lbp.value !== undefined && lbp.value !== null) ? lbp.value : (typeof lbp === 'number' ? lbp : null);
const decoded = um.decoded_payload;
const data = (decoded && typeof decoded === 'object') ? { ...decoded } : {};
delete data._msgid;
const entry = {
  sensorName,
  deviceId,
  receivedAt: ts,
  data,
  signal: {
    snr: rx.snr ?? null,
    channel_rssi: rx.channel_rssi ?? null,
    rssi: rx.rssi ?? null
  },
  last_battery_percentage: (lbp != null || bpVal != null) ? { value: bpVal, unit: '%' } : null,
  locationUser: locUser ? {
    latitude: locUser.latitude ?? null,
    longitude: locUser.longitude ?? null,
    altitude: locUser.altitude ?? null
  } : null,
  locationGateway: locGw ? {
    latitude: locGw.latitude ?? null,
    longitude: locGw.longitude ?? null,
    altitude: locGw.altitude ?? null
  } : null,
  ts
};
let lorawan = global.get('lorawan', 'file') || {};
let list = lorawan[sensorName] || [];
list.push(entry);
list.sort((a, b) => a.ts - b.ts);
if (list.length > MAX) list = list.slice(-MAX);
lorawan[sensorName] = list;
global.set('lorawan', lorawan, 'file');
msg.payload = entry;
return msg;

const TWO_HOURS = 12 * 60 * 60 * 1000;
const now = Date.now();
const lorawan = global.get('lorawan', 'file') || {};
const out = {};
for (const sensor of Object.keys(lorawan)) {
  const list = lorawan[sensor];
  if (!Array.isArray(list) || list.length === 0) continue;
  const latest = list[list.length - 1];
  const age = now - (latest.ts ?? latest.receivedAt ?? 0);
  if (age < TWO_HOURS) out[sensor] = latest;
}
msg.payload = out;
return msg;

