const ONE_HOUR = 1.5 * 60 * 60 * 1000;
const stationId = "A1QVv3Du";
/********************************/

/************ HELPERS ************/
function calculateDewPoint(temperature, humidity) {
    if (humidity < 0 || humidity > 100) {
        throw new Error("Humidity must be between 0 and 100");
    }
    return temperature - ((100 - humidity) / 5);
}

// Normalize timestamp from HA input_datetime
function normalizeTimestamp(ts) {
    if (!ts) return NaN;

    // Check if it's a number already (seconds or ms)
    let t = Number(ts);
    if (!isNaN(t)) {
        if (t < 1e12) t = t * 1000; // seconds → ms
        return t;
    }

    // Handle "YYYY-MM-DD HH:MM:SS" in UTC
    // Split into date & time parts
    const match = ts.match(/^(\d{4})-(\d{2})-(\d{2}) (\d{2}):(\d{2}):(\d{2})$/);
    if (match) {
        const [_, year, month, day, hour, min, sec] = match.map(Number);
        // JS Date.UTC uses 0-indexed months
        return Date.UTC(year, month - 1, day, hour, min, sec);
    }

    // fallback
    const parsed = Date.parse(ts);
    return isNaN(parsed) ? NaN : parsed;
}
